css:
.vbes-hero {
  background-color: {{bg_color}};
  color: {{text_color}};
  padding: 80px 24px;
  text-align: center;
}
.vbes-hero__inner {
  max-width: 800px;
  margin: 0 auto;
}
.vbes-hero__heading {
  font-size: 3rem;
  font-weight: 700;
  margin: 0 0 16px;
  line-height: 1.15;
}
.vbes-hero__subtitle {
  font-size: 1.25rem;
  opacity: 0.85;
  margin: 0 0 32px;
  line-height: 1.6;
}
.vbes-hero__btn {
  display: inline-block;
  padding: 14px 36px;
  background: {{button_color}};
  color: #ffffff;
  text-decoration: none;
  border-radius: 6px;
  font-size: 1rem;
  font-weight: 600;
  transition: opacity 0.2s;
}
.vbes-hero__btn:hover {
  opacity: 0.9;
}
@media (max-width: 768px) {
  .vbes-hero { padding: 48px 16px; }
  .vbes-hero__heading { font-size: 2rem; }
  .vbes-hero__subtitle { font-size: 1rem; }
}
